INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", "ペコリーヌとの出会い", 2834, 0, "フリーマーケット会場", 5118061, 10118, 8, 91002, "青空の下で謁見", 1, 40, 7, 2, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", "マホとの出会い", 2835, 0, "フリーマーケット会場", 5118062, 10118, 8, 91002, "未来の騎空団\nマスコット？", 1, 40, 7, 2, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", "アキノとの出会い", 2837, 0, "ランドソル市街地", 5118063, 10118, 8, 91002, "お嬢さまからの\n緊急依頼", 1, 40, 7, 2, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", "ジュンとの出会い", 4108402, 0, "フリーマーケット会場", 5118064, 10118, 8, 91002, "黄金色の悩みごと", 1, 40, 18, 2, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", "カオリとの出会い", 4107402, 0, "フリーマーケット会場", 5118065, 10118, 8, 91002, "白熱！　格闘大会！", 1, 40, 18, 2, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", "ニノンとの出会い", 9000227, 1, "オーエド町", 5118066, 10118, 8, 91002, "祭り太鼓はオーエドの華", 1, 40, 16, 2, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", "スズナとの出会い", 2101181, 0, "フリーマーケット会場", 5118067, 10118, 8, 91002, "人気者は遅れて\nやってくる", 1, 40, 19, 3, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", "ナナカとの出会い", 4109402, 0, "ランドソル市街地", 5118068, 10118, 8, 91002, "巫女・ミーツ・魔法少女", 1, 40, 18, 3, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", "キャル＆コッコロとの出会い", 4305402, 0, "フリーマーケット会場", 5118069, 10118, 8, 91002, "ネズ耳は二度なくなる", 1, 40, 18, 3, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", "ユカリとの出会い", 4101402, 0, "ランドソル市街地", 5118070, 10118, 8, 91002, "この出会いにカンパイ！", 1, 40, 18, 3, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", "アオイとの出会い", 4106402, 0, "ランドソル市街地", 5118071, 10118, 8, 91002, "陰陽アンサンブル", 1, 40, 18, 3, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", "シノブとの出会い", 2836, 1, "フリーマーケット会場", 5118072, 10118, 8, 91002, "運試し十番勝負！", 1, 40, 7, 3, 20063115);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, "オープニング", 0, 0, 0, 5118600, 10118, 0, 0, "彼女たちの新たな日常", 0, 0, 0, 1, 20063115);
